from pathlib import Path
import openpyxl
import datetime

def verify(workspace_path, external_services_path=None):
    # Try to find claim.xlsx - be flexible with naming
    claim_path = Path(workspace_path) / 'claim.xlsx'
    if not claim_path.exists():
        # Try glob for any xlsx with 'claim' in the name
        candidates = list(Path(workspace_path).glob('*laim*.xlsx'))
        if candidates:
            claim_path = candidates[0]
        else:
            # Also try recursively
            candidates = list(Path(workspace_path).rglob('*laim*.xlsx'))
            if candidates:
                claim_path = candidates[0]
            else:
                return {'pass': False, 'score': 0.0, 'feedback': 'claim.xlsx not found in workspace'}

    wb = openpyxl.load_workbook(claim_path)
    ws = wb.active

    headers = [str(cell.value).strip() if cell.value is not None else '' for cell in ws[1]]
    headers_upper = [h.upper().replace(' ', '_') for h in headers]

    # Find columns flexibly
    dos_col = None
    status_col = None
    era_received_col = None
    payment_posted_col = None
    tier_col = None
    freq_col = None
    paid_amount_col = None

    for i, h in enumerate(headers_upper):
        if dos_col is None and 'DOS' in h:
            dos_col = i
        if status_col is None and ('CLAIM_STATUS' in h or ('CLAIM' in h and 'STATUS' in h) or h == 'STATUS' or h == 'CLAIM_STATUS'):
            status_col = i
        if era_received_col is None and ('ERA' in h and 'RECEIVED' in h):
            era_received_col = i
        if payment_posted_col is None and ('PAYMENT_POSTED' in h or ('PAYMENT' in h and 'POSTED' in h)):
            payment_posted_col = i
        if tier_col is None and ('BENEFIT_TIER' in h or ('TIER' in h and 'BILLED' in h) or ('BENEFIT' in h and 'TIER' not in h)):
            tier_col = i
        if tier_col is None and 'BENEFIT' in h:
            tier_col = i
        if freq_col is None and ('FREQUENCY' in h or 'FREQ' in h):
            freq_col = i
        if paid_amount_col is None and ('PAID_AMOUNT' in h or ('PAID' in h and 'AMOUNT' in h) or h == 'PAID_AMOUNT'):
            paid_amount_col = i

    if dos_col is None:
        return {'pass': False, 'score': 0.0, 'feedback': f'DOS column not found. Headers: {headers}'}

    # Find the target row with DOS = 02/14/2026
    target_row = None
    for row in ws.iter_rows(min_row=2, values_only=True):
        dos_val = row[dos_col]
        if dos_val is None:
            continue
        dos_str = str(dos_val).strip()
        match = False
        if '02/14/2026' in dos_str or '2/14/2026' in dos_str or '2026-02-14' in dos_str:
            match = True
        if isinstance(dos_val, datetime.datetime):
            if dos_val.year == 2026 and dos_val.month == 2 and dos_val.day == 14:
                match = True
        elif isinstance(dos_val, datetime.date):
            if dos_val.year == 2026 and dos_val.month == 2 and dos_val.day == 14:
                match = True
        if match:
            target_row = row
            break

    if target_row is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'No row with DOS=02/14/2026 found in claim.xlsx'}

    issues = []
    details = []

    # Check Claim_Status = Denied
    if status_col is not None:
        status_val = str(target_row[status_col]).strip().lower() if target_row[status_col] is not None else ''
        if 'denied' in status_val or 'deny' in status_val or 'denial' in status_val:
            details.append(f'Claim_Status={target_row[status_col]}')
        else:
            issues.append(f'Claim_Status expected Denied, got: {target_row[status_col]}')
    else:
        issues.append(f'Claim_Status column not found. Headers: {headers}')

    # Check ERA_Received_Date = 04/08/2026 or 8 April 2026
    if era_received_col is not None:
        era_val = target_row[era_received_col]
        era_match = False
        if era_val is not None:
            if isinstance(era_val, (datetime.datetime, datetime.date)):
                if era_val.year == 2026 and era_val.month == 4 and era_val.day == 8:
                    era_match = True
            else:
                era_str = str(era_val).strip()
                if '04/08/2026' in era_str or '4/8/2026' in era_str or '2026-04-08' in era_str or '8 April 2026' in era_str or 'April 8' in era_str or '08-Apr' in era_str or '8-Apr' in era_str or '04-08-2026' in era_str:
                    era_match = True
        if era_match:
            details.append(f'ERA_Received_Date={era_val}')
        else:
            issues.append(f'ERA_Received_Date expected 04/08/2026 (8 April 2026), got: {era_val}')
    else:
        issues.append(f'ERA_Received_Date column not found. Headers: {headers}')

    # Check Payment_Posted_Date blank/null
    if payment_posted_col is not None:
        payment_val = target_row[payment_posted_col]
        if payment_val is None or str(payment_val).strip() in ('', 'None', 'nan', 'NaN', 'NULL', 'null', 'N/A', 'n/a'):
            details.append('Payment_Posted_Date=blank')
        else:
            issues.append(f'Payment_Posted_Date expected blank/null, got: {payment_val}')
    else:
        details.append('Payment_Posted_Date column not found (treated as blank)')

    # Check Benefit_Tier_Billed = Medical
    if tier_col is not None:
        tier_val = str(target_row[tier_col]).strip().lower() if target_row[tier_col] is not None else ''
        if 'medical' in tier_val:
            details.append(f'Benefit_Tier_Billed={target_row[tier_col]}')
        else:
            issues.append(f'Benefit_Tier_Billed expected Medical, got: {target_row[tier_col]}')
    else:
        issues.append(f'Benefit_Tier_Billed column not found. Headers: {headers}')

    # Check Paid_Amount = 0
    if paid_amount_col is not None:
        paid_val = target_row[paid_amount_col]
        paid_str = str(paid_val).strip().lower() if paid_val is not None else ''
        try:
            if paid_str in ('', 'none', 'nan', 'null', 'n/a'):
                numeric_val = 0.0
            else:
                numeric_val = float(paid_str.replace('$', '').replace(',', ''))
            if abs(numeric_val) < 0.01:
                details.append(f'Paid_Amount={paid_val}')
            else:
                issues.append(f'Paid_Amount expected 0, got: {paid_val}')
        except (ValueError, TypeError):
            if paid_str in ('', 'none', 'nan', 'null', 'n/a', '0', '0.0', '0.00'):
                details.append(f'Paid_Amount={paid_val} (treated as 0)')
            else:
                issues.append(f'Paid_Amount expected 0, got: {paid_val}')
    else:
        issues.append(f'Paid_Amount column not found. Headers: {headers}')

    # Check Claim_Frequency_Code = 1
    if freq_col is not None:
        freq_val = str(target_row[freq_col]).strip() if target_row[freq_col] is not None else ''
        if freq_val in ('1', '1.0', '01'):
            details.append(f'Claim_Frequency_Code={freq_val}')
        else:
            issues.append(f'Claim_Frequency_Code expected 1, got: {freq_val}')
    else:
        issues.append(f'Claim_Frequency_Code column not found. Headers: {headers}')

    if issues:
        return {'pass': False, 'score': 0.0, 'feedback': 'Issues found in claim.xlsx row DOS=02/14/2026: ' + '; '.join(issues)}

    return {'pass': True, 'score': 1.0, 'feedback': 'claim.xlsx row DOS=02/14/2026 verified: ' + '; '.join(details)}

