from pathlib import Path

def verify(workspace_path, external_services_path=None):
    ws = Path(workspace_path)

    all_files = [f for f in ws.rglob('*') if f.is_file()]

    # --- Pass 1: exact stem match, PDF only ---
    target_stem = 'appeal_l1_02142026'
    for f in all_files:
        if f.suffix.lower() != '.pdf':
            continue
        if f.stem.lower() == target_stem:
            return {
                'pass': True,
                'score': 1.0,
                'feedback': f'Found appeal_L1_02142026.pdf at {f.relative_to(ws)}'
            }

    # --- Pass 2: normalised separators (hyphens → underscores), PDF only ---
    for f in all_files:
        if f.suffix.lower() != '.pdf':
            continue
        normalised = f.stem.lower().replace('-', '_').replace(' ', '_')
        if normalised == target_stem:
            return {
                'pass': True,
                'score': 1.0,
                'feedback': (
                    f'Found matching PDF with alternate separators: '
                    f'{f.name} (at {f.relative_to(ws)})'
                )
            }

    # --- Pass 3: component match, PDF only ---
    date_variants = ['02142026', '02_14_2026', '02-14-2026']
    for f in all_files:
        if f.suffix.lower() != '.pdf':
            continue
        n = f.name.lower()
        if 'appeal' in n and 'l1' in n and any(d in n for d in date_variants):
            return {
                'pass': True,
                'score': 1.0,
                'feedback': (
                    f'Found appeal letter PDF (component match): '
                    f'{f.name} (at {f.relative_to(ws)})'
                )
            }

    # --- Diagnosis: did the model produce the file in a non-PDF format? ---
    non_pdf_matches = [
        f for f in all_files
        if f.suffix.lower() != '.pdf'
        and 'appeal' in f.name.lower()
        and 'l1' in f.name.lower()
        and any(d in f.name.lower() for d in date_variants)
    ]
    if non_pdf_matches:
        names = [f.name for f in non_pdf_matches]
        return {
            'pass': False,
            'score': 0.0,
            'feedback': (
                f'Appeal letter found but not in PDF format: {names}. '
                f'The criterion requires a .pdf file. '
                f'Rename or re-export the file as appeal_L1_02142026.pdf.'
            )
        }

    all_names = [f.name for f in all_files]
    return {
        'pass': False,
        'score': 0.0,
        'feedback': (
            f'No appeal_L1_02142026.pdf found in workspace. '
            f'Expected a .pdf file whose name contains "appeal", "l1", '
            f'and date "02142026". '
            f'Files present: {all_names}'
        )
    }

from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'external_services_path is None; cannot check mailbox'}

    mailbox_path = Path(external_services_path) / 'mailbox.json'
    if not mailbox_path.exists():
        return {'pass': False, 'score': 0.0, 'feedback': 'mailbox.json not found in external_services_path'}

    with open(mailbox_path, 'r') as f:
        data = json.load(f)

    emails = data.get('emails', [])

    # Find sent emails to the appeals address (case-insensitive)
    target_emails = [
        e for e in emails
        if str(e.get('folder', '')).lower() == 'sent'
        and 'appeals@silverpath-claims.com' in str(e.get('to_addr', '')).lower()
    ]

    if len(target_emails) == 0:
        return {'pass': False, 'score': 0.0, 'feedback': 'No sent email to appeals@silverpath-claims.com found'}

    if len(target_emails) > 1:
        return {'pass': False, 'score': 0.0, 'feedback': f'Expected exactly 1 sent email to appeals@silverpath-claims.com, found {len(target_emails)}'}

    email = target_emails[0]

    # Check subject for required substrings
    subject = str(email.get('subject', ''))
    required_substrings = [
        'APPEAL L1',
        'CareIG',
        'Holloway',
        'MemberID:',
        'SPA-00291847',
        'DOS:',
        '02/14/2026',
        'Claim:',
        'CLM-REF-20260218-9931',
        'CARC:',
        'CO-97'
    ]

    # Case-sensitive IDs that must match exactly
    exact_match_required = {'SPA-00291847', 'CLM-REF-20260218-9931', 'CO-97', '02/14/2026'}

    missing = []
    for s in required_substrings:
        if s in subject:
            continue
        # For non-exact fields, try case-insensitive
        if s not in exact_match_required and s.upper() in subject.upper():
            continue
        missing.append(s)

    if missing:
        return {'pass': False, 'score': 0.0, 'feedback': f'Email subject missing required substrings: {missing}. Subject was: {subject}'}

    # Check attachments
    attachments = email.get('attachments', [])
    attach_names = []
    for a in attachments:
        if isinstance(a, str):
            attach_names.append(a)
        elif isinstance(a, dict):
            name = a.get('filename', a.get('name', str(a)))
            attach_names.append(name)
        else:
            attach_names.append(str(a))

    attach_names_lower = [n.lower() for n in attach_names]

    # Required exact attachment filenames
    required_exact_attachments = [
        'appeal_L1_02142026.pdf',
        'claim_02142026_Holloway_SilverPath.pdf',
        'pa_approval_SilverPath_Holloway.pdf',
        'lmn_DrOsei_Holloway.pdf',
        'era_02142026_SilverPath.pdf'
    ]

    missing_attachments = []
    for req in required_exact_attachments:
        # Check case-insensitive
        found = any(req.lower() in n for n in attach_names_lower)
        if not found:
            missing_attachments.append(req)

    if missing_attachments:
        return {'pass': False, 'score': 0.0, 'feedback': f'Missing required attachments: {missing_attachments}. Found attachments: {attach_names}'}

    # Check for an attachment whose filename contains 'visit_note' (case-insensitive)
    found_visit_note = any('visit_note' in n.lower() for n in attach_names)
    if not found_visit_note:
        return {'pass': False, 'score': 0.0, 'feedback': f'No attachment with filename containing "visit_note" found. Found attachments: {attach_names}'}

    # Total expected: 5 exact + 1 visit_note = 6
    # Be lenient: as long as all required ones are present, pass even if there are extras

    return {
        'pass': True,
        'score': 1.0,
        'feedback': f'Sent email to appeals@silverpath-claims.com found with correct subject substrings and all required attachments. Subject: {subject}. Attachments: {attach_names}'
    }

from pathlib import Path
import json
from datetime import datetime

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'external_services_path is None; cannot check mailbox'}

    mailbox_path = Path(external_services_path) / 'mailbox.json'
    if not mailbox_path.exists():
        return {'pass': False, 'score': 0.0, 'feedback': 'mailbox.json not found in external_services_path'}

    with open(mailbox_path, 'r') as f:
        data = json.load(f)

    emails = data.get('emails', [])
    cutoff = datetime(2026, 4, 1)

    violations = []
    for e in emails:
        to_addr = str(e.get('to_addr', ''))
        if 'billing@silverpath-claims.com' in to_addr.lower():
            date_str = str(e.get('date', ''))
            try:
                email_date = datetime.fromisoformat(date_str[:10])
                if email_date >= cutoff:
                    violations.append(f"Subject: {e.get('subject', 'N/A')}, Date: {date_str}")
            except Exception:
                pass

    if violations:
        return {'pass': False, 'score': 0.0, 'feedback': f'Found emails to billing@silverpath-claims.com on/after 2026-04-01: {violations}'}

    return {'pass': True, 'score': 1.0, 'feedback': 'No emails sent to billing@silverpath-claims.com on or after 2026-04-01 (no corrected claim submitted to payer)'}

