    def col_idx(substr):
        return next((i for i, h in enumerate(headers) if substr in h), None)

    dos_col = col_idx('DOS')
    carc_col = col_idx('CARC')
    level_col = col_idx('LEVEL')
    subdate_col = col_idx('SUBMITTED_DATE') or col_idx('SUBMIT')
    status_col = col_idx('STATUS')
    payer_col = col_idx('PAYER')

    target_rows = []
    for row in rows[1:]:
        if dos_col is not None:
            dos_val = str(row[dos_col]).strip() if row[dos_col] is not None else ''
            if '02/14/2026' in dos_val or '2026-02-14' in dos_val:
                target_rows.append(row)

    if len(target_rows) != 1:
        return {'pass': False, 'score': 0.0, 'feedback': f'Expected exactly 1 row with DOS=02/14/2026 in appeals_log.xlsx, found {len(target_rows)}'}

    row = target_rows[0]
    issues = []

    if carc_col is not None:
        carc_val = str(row[carc_col]).strip() if row[carc_col] is not None else ''
        if 'CO-97' not in carc_val.upper() and 'CO97' not in carc_val.upper():
            issues.append(f'CARC_Code expected CO-97, got: {carc_val}')
    else:
        issues.append('CARC_Code column not found')

    if level_col is not None:
        level_val = str(row[level_col]).strip().upper() if row[level_col] is not None else ''
        if 'L1' not in level_val:
            issues.append(f'Appeal_Level expected L1, got: {row[level_col]}')
    else:
        issues.append('Appeal_Level column not found')

    if subdate_col is not None:
        date_val = str(row[subdate_col]).strip() if row[subdate_col] is not None else ''
        if '04/08/2026' not in date_val and '2026-04-08' not in date_val:
            issues.append(f'Appeal_Submitted_Date expected 04/08/2026, got: {date_val}')
    else:
        issues.append('Appeal_Submitted_Date column not found')

    if status_col is not None:
        status_val = str(row[status_col]).strip().lower() if row[status_col] is not None else ''
        if 'submitted' not in status_val:
            issues.append(f'Appeal_Status expected Submitted, got: {row[status_col]}')
    else:
        issues.append('Appeal_Status column not found')

    if payer_col is not None:
        payer_val = str(row[payer_col]).strip() if row[payer_col] is not None else ''
        if 'SILVERPATH' not in payer_val.upper():
            issues.append(f'Payer expected SilverPath Medicare Advantage, got: {payer_val}')
    else:
        issues.append('Payer column not found')

    if issues:
        return {'pass': False, 'score': 0.0, 'feedback': 'Issues in appeals_log.xlsx DOS=02/14/2026 row: ' + '; '.join(issues)}

    return {'pass': True, 'score': 1.0, 'feedback': 'appeals_log.xlsx has 4 rows, DOS=02/14/2026 row has CARC_Code=CO-97, Appeal_Level=L1, Appeal_Submitted_Date=04/08/2026, Appeal_Status=Submitted, Payer=SilverPath Medicare Advantage'}

