        'Member ID: BCR-00184523',
        'DOS: 12/09/2025',
        'Claim Reference: CLM-REF-20251215-6612',
        'Billed: $5,840.00'
    ]

    required_attachment = 'appeal_L1_12092025.pdf'

    def normalize(text):
        """Normalize whitespace for flexible matching."""
        return re.sub(r'\s+', ' ', str(text)).strip()

    def check_subject(subject):
        subj_norm = normalize(subject).lower()
        # Also try without spaces around colons
        subj_no_space = re.sub(r'\s*:\s*', ':', subj_norm)
        missing = []
        for s in required_subject_substrings:
            s_lower = s.lower()
            s_no_space = re.sub(r'\s*:\s*', ':', s_lower)
            # Try multiple matching strategies
            if s_lower in subj_norm:
                continue
            if s_no_space in subj_no_space:
                continue
            # Try without space: "MemberID:" might appear as "Member ID:" or "MemberID:"
            if s == 'MemberID:':
                if 'memberid:' in subj_norm or 'member id:' in subj_norm or 'memberid :' in subj_norm:
                    continue
            missing.append(s)
        return missing

    def check_body(body):
        body_norm = normalize(body)
        missing = []
        for s in required_body_substrings:
            # Case-insensitive check with normalized whitespace
            s_norm = normalize(s)
            if s_norm.lower() in body_norm.lower():
                continue
            # Try with em-dash variants
            s_variants = [
                s_norm,
                s_norm.replace('\u2014', '-'),
                s_norm.replace('\u2014', '--'),
                s_norm.replace('-', '\u2014'),
            ]
            found = False
            for variant in s_variants:
                if variant.lower() in body_norm.lower():
                    found = True
                    break
            if not found:
                missing.append(s)
        return missing

    def get_attachment_names(attachments):
        names = []
        for a in (attachments or []):
            if isinstance(a, str):
                names.append(a.strip())
            elif isinstance(a, dict):
                name = a.get('filename', a.get('name', a.get('file_name', '')))
                names.append(str(name).strip())
            else:
                names.append(str(a).strip())
        return names

    def check_attachment(email_obj):
        att_names = get_attachment_names(email_obj.get('attachments', []))
        for name in att_names:
            if name.lower() == required_attachment.lower():
                return True
        return False

    # Find emails that match all criteria
    fully_matching = []
    partial_details = []

    for email in target_emails:
        subject = str(email.get('subject', ''))
        body = str(email.get('body_text', email.get('body', '')))

        subj_missing = check_subject(subject)
        body_missing = check_body(body)
        has_attachment = check_attachment(email)

        if not subj_missing and not body_missing and has_attachment:
            fully_matching.append(email)
        else:
            partial_details.append({
                'subject': subject[:100],
                'subj_missing': subj_missing,
                'body_missing': body_missing,
                'has_attachment': has_attachment
            })

    if len(fully_matching) >= 2:
        return {
            'pass': True,
            'score': 1.0,
            'feedback': f'Found exactly 3 sent emails to appeals@bluecrest-health.com. {len(fully_matching)} of them have correct subjects containing all required substrings, correct body content, and the required attachment ({required_attachment}).'
        }

    # If we didn't find 2 fully matching, try a more lenient approach:
    # Check subject and body separately, being more lenient on subject formatting
    lenient_matching = []
    for email in target_emails:
        subject = str(email.get('subject', ''))
        body = str(email.get('body_text', email.get('body', '')))
        subj_norm = normalize(subject).lower()

        # Lenient subject check: just check key identifiers are present
        key_subject_items = ['appeal', 'l1', 'careig', 'holloway', 'bcr-00184523',
                             '12/09/2025', 'clm-ref-20251215-6612', 'pi-204']
        subj_key_missing = [k for k in key_subject_items if k not in subj_norm]

        body_missing = check_body(body)
        has_attachment = check_attachment(email)

        if not subj_key_missing and not body_missing and has_attachment:
            lenient_matching.append(email)

    if len(lenient_matching) >= 2:
        return {
            'pass': True,
            'score': 1.0,
            'feedback': f'Found exactly 3 sent emails to appeals@bluecrest-health.com. {len(lenient_matching)} of them have correct subjects (lenient match), correct body content, and the required attachment ({required_attachment}).'
        }

    # Build detailed failure feedback
    feedback_parts = [f'Expected at least 2 fully matching emails out of 3 sent to appeals@bluecrest-health.com.']
    feedback_parts.append(f'Fully matching (strict): {len(fully_matching)}, Lenient matching: {len(lenient_matching)}')
    for i, detail in enumerate(partial_details):
        feedback_parts.append(
            f'Email {i+1} (subject: "{detail["subject"]}..."): '
            f'subject missing={detail["subj_missing"]}, '
            f'body missing={detail["body_missing"]}, '
            f'has_attachment={detail["has_attachment"]}'
        )
    for i, email in enumerate(fully_matching):
        feedback_parts.append(f'Matching email {i+1} subject: "{str(email.get("subject", ""))[:100]}"')

    score = 0.0
    if len(fully_matching) == 1 or len(lenient_matching) == 1:
        score = 0.5

    return {
        'pass': False,
        'score': score,
        'feedback': ' | '.join(feedback_parts)
    }

from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'external_services_path is None; cannot check Slack'}

    slack_path = Path(external_services_path) / 'slack_data.json'
    if not slack_path.exists():
        return {'pass': False, 'score': 0.0, 'feedback': 'slack_data.json not found in external_services_path'}

    with open(slack_path, 'r') as f:
        data = json.load(f)

    channels = data.get('channels', {})
    messages = data.get('messages', {})

    # Find #billing-appeals channel (be flexible with naming)
    billing_appeals_id = None
    for ch_id, ch_info in channels.items():
        ch_name = ch_info.get('name', '').lower().replace('-', '').replace('_', '').replace(' ', '')
        if ch_name == 'billingappeals':
            billing_appeals_id = ch_id
            break

    if billing_appeals_id is None:
        return {'pass': False, 'score': 0.0, 'feedback': f'Channel #billing-appeals not found in slack_data.json. Available channels: {[ch.get("name") for ch in channels.values()]}'}

    channel_messages = messages.get(billing_appeals_id, [])

    # Required content pieces to find in a message
    # Be loose: case-insensitive where appropriate, flexible date formats, flexible separators
    required_checks = {
        'APPEAL FILED L1': lambda t: 'appeal' in t.lower() and ('filed' in t.lower() or 'file' in t.lower()) and ('l1' in t.lower() or 'level 1' in t.lower() or 'level1' in t.lower()),
        'Holloway_DOB_03141961': lambda t: 'holloway' in t.lower() and ('03141961' in t.replace('/', '').replace('-', '').replace(' ', '') or '03/14/1961' in t or '03-14-1961' in t or '3/14/1961' in t),
        '02/14/2026': lambda t: any(d in t for d in ['02/14/2026', '2/14/2026', '02-14-2026', '2-14-2026', '2026-02-14', '02142026']),
        'SilverPath': lambda t: 'silverpath' in t.lower().replace(' ', '').replace('-', '').replace('_', ''),
        'CO-97': lambda t: 'co-97' in t.lower() or 'co 97' in t.lower() or 'co97' in t.lower(),
    }

    best_match_count = 0
    best_match_text = ''
    matched_keys_best = []

    for msg in channel_messages:
        text = str(msg.get('text', ''))
        matched_keys = []
        for key, check_fn in required_checks.items():
            if check_fn(text):
                matched_keys.append(key)

        if len(matched_keys) > best_match_count:
            best_match_count = len(matched_keys)
            best_match_text = text
            matched_keys_best = matched_keys

        if len(matched_keys) == len(required_checks):
            return {'pass': True, 'score': 1.0, 'feedback': f'Found matching message in #billing-appeals containing all required elements: {text[:300]}'}

    # Also check all messages across all channels in case channel name matching failed
    for ch_id, ch_msgs in messages.items():
        if ch_id == billing_appeals_id:
            continue
        for msg in ch_msgs:
            text = str(msg.get('text', ''))
            matched_keys = []
            for key, check_fn in required_checks.items():
                if check_fn(text):
                    matched_keys.append(key)
            if len(matched_keys) > best_match_count:
                best_match_count = len(matched_keys)
                best_match_text = text
                matched_keys_best = matched_keys
                # Note: don't pass here since it's wrong channel, but track for feedback

    missing = [k for k in required_checks if k not in matched_keys_best]
    return {
        'pass': False,
        'score': best_match_count / len(required_checks) * 0.5,  # partial credit
        'feedback': f'No message in #billing-appeals found containing all required elements. '
                    f'Best match had {best_match_count}/{len(required_checks)} elements. '
                    f'Missing: {missing}. '
                    f'Found {len(channel_messages)} messages in #billing-appeals. '
                    f'Best matching text: "{best_match_text[:300]}"'
    }

