        if isinstance(v, (datetime.datetime, datetime.date)):
            return v.strftime("%m/%d/%Y")
        s = str(v).strip()
        for fmt in ["%m/%d/%Y", "%Y-%m-%d", "%m-%d-%Y", "%m/%d/%y", "%Y/%m/%d", "%d/%m/%Y"]:
            try:
                dt = datetime.datetime.strptime(s, fmt)
                return dt.strftime("%m/%d/%Y")
            except ValueError:
