from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    # We need to check mailbox.json for the absence of a specific email.
    # The mailbox.json could be in the workspace or in external_services_path.

    mailbox_path = None

    # Check external_services_path first
    if external_services_path:
        candidate = Path(external_services_path) / "mailbox.json"
        if candidate.exists():
            mailbox_path = candidate

    # Also check workspace_path
    if mailbox_path is None:
        candidate = Path(workspace_path) / "mailbox.json"
        if candidate.exists():
            mailbox_path = candidate

    if mailbox_path is None:
        # If no mailbox.json found at all, the email trivially doesn't exist -> PASS
        return {"pass": True, "score": 1.0, "feedback": "No mailbox.json found, so the prohibited email does not exist. PASS."}

    try:
        with open(mailbox_path, 'r', encoding='utf-8') as f:
            data = json.load(f)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Failed to read mailbox.json: {e}"}

    emails = data.get("emails", [])

    # Define date patterns that all represent February 14, 2026
    date_patterns = [
        r'02/14/2026',
        r'02-14-2026',
        r'2/14/2026',
        r'2-14-2026',
        r'14/02/2026',
        r'14-02-2026',
        r'2026-02-14',
        r'2026/02/14',
        r'Feb(?:ruary)?\s*14,?\s*2026',
        r'14\s*Feb(?:ruary)?,?\s*2026',
    ]

    def subject_contains_date(subject):
        for pat in date_patterns:
            if re.search(pat, subject, re.IGNORECASE):
                return True
        return False

    violating_emails = []

    for email in emails:
        to_addr = email.get("to_addr", "").strip().lower()
        subject = email.get("subject", "")

        # Check to_addr matches
        if to_addr != "m.holloway@emailhost.com":
            continue

        # Check subject contains "CareIG Statement of Account" (case-insensitive)
        if "careig statement of account" not in subject.lower():
            continue

        # Check subject contains the date 02/14/2026 in any format
        if subject_contains_date(subject):
            violating_emails.append(email)

    if len(violating_emails) > 0:
        details = []
        for e in violating_emails:
            details.append(f"  - email_id={e.get('email_id','?')}, to={e.get('to_addr','?')}, subject='{e.get('subject','?')}', folder={e.get('folder','?')}")
        detail_str = "\n".join(details)
        return {
            "pass": False,
            "score": 0.0,
            "feedback": f"FAIL: Found {len(violating_emails)} email(s) that should NOT exist (to=m.holloway@emailhost.com, subject containing 'CareIG Statement of Account' and date 02/14/2026):\n{detail_str}"
        }

    return {
        "pass": True,
        "score": 1.0,
        "feedback": "PASS: No email found in mailbox.json with to_addr='m.holloway@emailhost.com' and subject containing both 'CareIG Statement of Account' and the date 02/14/2026."
    }

from pathlib import Path
import re

def verify(workspace_path, external_services_path=None):
    workspace = Path(workspace_path)
    pdf_file = None

    # Search for the file - try exact name and case-insensitive
    target_name = "appeal_L1_02142026.pdf"
    candidates = list(workspace.rglob("*.pdf"))
    for c in candidates:
        if c.name.lower() == target_name.lower():
            pdf_file = c
            break

    # Also try broader matching in case of slight name variations
    if pdf_file is None:
        for c in candidates:
            if "appeal" in c.name.lower() and "02142026" in c.name:
                pdf_file = c
                break

    if pdf_file is None:
        return {"pass": False, "score": 0.0, "feedback": f"File '{target_name}' not found in workspace. PDF files found: {[str(c.relative_to(workspace)) for c in candidates]}"}

    # Extract text from PDF
    text = ""
    try:
        import pdfplumber
        with pdfplumber.open(str(pdf_file)) as pdf:
            for page in pdf.pages:
                page_text = page.extract_text()
                if page_text:
                    text += page_text + "\n"
    except Exception as e1:
        try:
            import PyPDF2
            with open(str(pdf_file), 'rb') as f:
                reader = PyPDF2.PdfReader(f)
                for page in reader.pages:
                    page_text = page.extract_text()
                    if page_text:
                        text += page_text + "\n"
        except Exception as e2:
            return {"pass": False, "score": 0.0, "feedback": f"Could not read PDF. pdfplumber error: {e1}; PyPDF2 error: {e2}"}

    if not text.strip():
        return {"pass": False, "score": 0.0, "feedback": "PDF file exists but no text could be extracted."}

    # Normalize text for searching
    text_lower = text.lower()
    # Also create a version with collapsed whitespace for matching longer strings
    text_collapsed = re.sub(r'\s+', ' ', text).strip()
    text_collapsed_lower = text_collapsed.lower()

    checks = []
    total = 0
    passed = 0

    # Helper function for flexible matching
    def check_present(label, patterns, required=True):
        nonlocal total, passed
        total += 1
        for pattern in patterns:
            if pattern.lower() in text_collapsed_lower:
                passed += 1
                checks.append(f"PASS: {label} - found '{pattern}'")
                return True
        checks.append(f"FAIL: {label} - none of {patterns} found in PDF text")
        return False

    # 1. Date = 04/08/2026
    check_present("Date 04/08/2026", [
        "04/08/2026", "04-08-2026", "april 8, 2026", "april 08, 2026",
        "4/8/2026", "8 april 2026", "08 april 2026"
    ])

    # 2. Margaret
    check_present("Patient first name 'Margaret'", ["margaret"])

    # 3. Holloway
    check_present("Patient last name 'Holloway'", ["holloway"])

    # 4. Member ID SPA-00291847
    check_present("Member ID SPA-00291847", [
        "spa-00291847", "spa00291847", "spa 00291847"
    ])

    # 5. DOS 02/14/2026
    check_present("DOS 02/14/2026", [
        "02/14/2026", "02-14-2026", "2/14/2026", "february 14, 2026",
        "february 14 2026", "14 february 2026"
    ])

    # 6. Claim # CLM-REF-20260218-9931
    check_present("Claim # CLM-REF-20260218-9931", [
        "clm-ref-20260218-9931", "clm ref 20260218 9931"
    ])

    # 7. CARC CO-97
    check_present("CARC CO-97", [
        "co-97", "co 97", "co97"
    ])

    # 8. Billed $6,140.00
    check_present("Billed $6,140.00", [
        "$6,140.00", "$6140.00", "6,140.00", "6140.00", "$ 6,140.00", "$6,140"
    ])

    # 9. Letter body: #SPA-PA-2026-3302 was approved for Octagam 10% 40g, effective 01/28/2026 through 07/28/2026
    # Check for the key components since exact whitespace/formatting may vary
    spa_pa_found = False
    spa_patterns = ["spa-pa-2026-3302"]
    for p in spa_patterns:
        if p in text_collapsed_lower:
            spa_pa_found = True
            break

    octagam_found = False
    octagam_patterns = ["octagam 10% 40g", "octagam 10% 40 g", "octagam10% 40g", "octagam 10%, 40g", "octagam 10% 40g"]
    for p in octagam_patterns:
        if p in text_collapsed_lower:
            octagam_found = True
            break
    # Also try regex for more flexible matching
    if not octagam_found:
        if re.search(r'octagam\s*10\s*%\s*,?\s*40\s*g', text_collapsed_lower):
            octagam_found = True

    dates_found = False
    start_date_found = any(d in text_collapsed for d in ["01/28/2026", "1/28/2026", "01-28-2026"]) or \
                        any(d in text_collapsed_lower for d in ["january 28, 2026", "january 28 2026"])
    end_date_found = any(d in text_collapsed for d in ["07/28/2026", "7/28/2026", "07-28-2026"]) or \
                     any(d in text_collapsed_lower for d in ["july 28, 2026", "july 28 2026"])
    if start_date_found and end_date_found:
        dates_found = True

    approved_phrase_found = "approved" in text_collapsed_lower and spa_pa_found and octagam_found and dates_found

    total += 1
    if approved_phrase_found:
        passed += 1
        checks.append("PASS: Letter body contains approval phrase with SPA-PA-2026-3302, Octagam 10% 40g, and effective dates 01/28/2026 through 07/28/2026")
    else:
        details = []
        if not spa_pa_found:
            details.append("SPA-PA-2026-3302 not found")
        if not octagam_found:
            details.append("Octagam 10% 40g not found")
        if not dates_found:
            if not start_date_found:
                details.append("Start date 01/28/2026 not found")
            if not end_date_found:
                details.append("End date 07/28/2026 not found")
        if "approved" not in text_collapsed_lower:
            details.append("'approved' not found")
        checks.append(f"FAIL: Approval phrase incomplete - {'; '.join(details)}")

    # 10. D83.9
    check_present("Diagnosis code D83.9", ["d83.9"])

    # 11. Contracted rate $4,800.00
    check_present("Contracted rate $4,800.00", [
        "$4,800.00", "$4800.00", "4,800.00", "4800.00", "$ 4,800.00", "$4,800"
    ])

    score = passed / total if total > 0 else 0.0
    all_passed = (passed == total)

    feedback = f"Checked {total} criteria, {passed} passed, {total - passed} failed.\n"
    feedback += "\n".join(checks)

    # Show a snippet of the extracted text on failure for debugging
    if not all_passed:
        snippet = text_collapsed[:2000]
        feedback += f"\n\n--- Extracted PDF text (first 2000 chars) ---\n{snippet}"

    return {"pass": all_passed, "score": score, "feedback": feedback}

