    # Find column indices by header row (row 1)
    headers = {}
    for col_idx, cell in enumerate(ws[1], start=1):
        if cell.value is not None:
            headers[str(cell.value).strip().upper()] = col_idx

    # Try to locate relevant columns
    case_id_col = None
    datetime_col = None
    action_col = None

    for key, idx in headers.items():
        if 'CASE' in key and 'ID' in key:
            case_id_col = idx
        if key == 'DATETIME':                          # FIX: was ('DATE' in key or 'TIME' in key or key == 'DATETIME')
            datetime_col = idx                         #      'DATE' in key matches FILE_UPDATED and FIELD_UPDATED,
        if key == 'ACTION':                            #      overwriting datetime_col with the wrong column index.
            action_col = idx                           #      Exact match eliminates the substring collision.

    if case_id_col is None or datetime_col is None or action_col is None:
        return {"pass": False, "score": 0.0, "feedback": f"Could not find required columns. Headers found: {headers}"}

    def normalize(val):
        if val is None:
            return ""
        return str(val).strip()

    def check_case_id(val):
        normed = normalize(val).lower()
        return normed == "holloway_dob_03141961"

    def check_date(val):
        if val is None:
            return False
        import datetime as dt
        if isinstance(val, (dt.datetime, dt.date)):
            d = val.date() if isinstance(val, dt.datetime) else val
            return d.month == 4 and d.day == 8 and d.year == 2026
        s = normalize(val)
        patterns = [
            r'0?4[/\-]0?8[/\-]2026',
            r'2026[/\-]0?4[/\-]0?8',
            r'April\s+8,?\s+2026',
            r'8\s+April\s+2026',
            r'04082026',
        ]
        for p in patterns:
            if re.search(p, s, re.IGNORECASE):
                return True
        return False

    def check_action_denial(val):
        normed = normalize(val).lower()
        normed_dashes = re.sub(r'[\u2014\u2013\u2012\u2015\-]+', '-', normed)
        if 'denial received' in normed_dashes and ('co-97' in normed_dashes or 'co 97' in normed_dashes or 'co97' in normed_dashes):
            return True
        return False

    def check_action_appeal(val):
        normed = normalize(val).lower()
        return 'appeal submitted' in normed

    # Check row 36
    row36_case   = ws.cell(row=36, column=case_id_col).value
    row36_date   = ws.cell(row=36, column=datetime_col).value
    row36_action = ws.cell(row=36, column=action_col).value

    # Check row 37
    row37_case   = ws.cell(row=37, column=case_id_col).value
    row37_date   = ws.cell(row=37, column=datetime_col).value
    row37_action = ws.cell(row=37, column=action_col).value

    issues = []
    passes = []

    if check_case_id(row36_case):
        passes.append(f"Row 36 CASE_ID: '{row36_case}' matches")
    else:
        issues.append(f"Row 36 CASE_ID: expected 'Holloway_DOB_03141961', got '{row36_case}'")

    if check_date(row36_date):
        passes.append(f"Row 36 Datetime: '{row36_date}' matches 04/08/2026")
    else:
        issues.append(f"Row 36 Datetime: expected date 04/08/2026, got '{row36_date}'")

    if check_action_denial(row36_action):
        passes.append(f"Row 36 Action: '{row36_action}' matches 'Denial Received — CO-97'")
    else:
        issues.append(f"Row 36 Action: expected 'Denial Received — CO-97', got '{row36_action}'")

    if check_case_id(row37_case):
        passes.append(f"Row 37 CASE_ID: '{row37_case}' matches")
    else:
        issues.append(f"Row 37 CASE_ID: expected 'Holloway_DOB_03141961', got '{row37_case}'")

    if check_date(row37_date):
        passes.append(f"Row 37 Datetime: '{row37_date}' matches 04/08/2026")
    else:
        issues.append(f"Row 37 Datetime: expected date 04/08/2026, got '{row37_date}'")

    if check_action_appeal(row37_action):
        passes.append(f"Row 37 Action: '{row37_action}' matches 'Appeal Submitted'")
    else:
        issues.append(f"Row 37 Action: expected 'Appeal Submitted', got '{row37_action}'")

    total_checks = 6
    passed_checks = total_checks - len(issues)
    score = passed_checks / total_checks

    if len(issues) == 0:
        return {"pass": True, "score": 1.0, "feedback": "All checks passed. " + "; ".join(passes)}
    else:
        return {"pass": False, "score": score, "feedback": "Issues found: " + "; ".join(issues) + ". Passed: " + "; ".join(passes)}

from pathlib import Path
import json
import re


def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0, "feedback": "external_services_path is None; cannot check slack_data.json."}

    slack_path = Path(external_services_path) / "slack_data.json"
    if not slack_path.exists():
        return {"pass": False, "score": 0.0, "feedback": f"File not found: {slack_path}"}

    try:
        with open(slack_path, "r", encoding="utf-8") as f:
            slack_data = json.load(f)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Error reading slack_data.json: {e}"}

    if not isinstance(slack_data, dict):
        return {"pass": False, "score": 0.0, "feedback": "slack_data.json top-level is not a dict."}

    # Collect all messages from billing-appeals channel using multiple possible structures
    all_channel_messages = []

    channels_map = slack_data.get("channels", {})
    messages_map = slack_data.get("messages", {})

    # Standard format: channels dict keyed by channel ID, messages dict keyed by channel ID
    if isinstance(channels_map, dict) and isinstance(messages_map, dict):
        for ch_id, ch_info in channels_map.items():
            ch_name = ""
            if isinstance(ch_info, dict):
                ch_name = ch_info.get("name", "") or ch_info.get("channel_name", "") or ""
            elif isinstance(ch_info, str):
                ch_name = ch_info
            if "billing-appeals" in ch_name.lower().replace(" ", "-").replace("_", "-"):
                msgs = messages_map.get(ch_id, [])
                if isinstance(msgs, list):
                    all_channel_messages.extend(msgs)
                break
        # Also check if messages_map is keyed by channel name directly
        if not all_channel_messages:
            for key, msgs in messages_map.items():
                if "billing-appeals" in key.lower().replace(" ", "-").replace("_", "-"):
                    if isinstance(msgs, list):
                        all_channel_messages.extend(msgs)
                    break

    # Fallback: channels is a dict with channel names as keys containing messages
    if not all_channel_messages and isinstance(channels_map, dict):
        for ch_name, ch_data in channels_map.items():
            if "billing-appeals" in ch_name.lower().replace(" ", "-").replace("_", "-"):
                if isinstance(ch_data, dict) and "messages" in ch_data:
                    all_channel_messages.extend(ch_data["messages"])
                elif isinstance(ch_data, list):
                    all_channel_messages.extend(ch_data)
                break

    # Fallback: channels is a list of channel objects
    if not all_channel_messages and isinstance(channels_map, list):
        for ch in channels_map:
            if isinstance(ch, dict):
                ch_name = ch.get("name", "") or ch.get("channel_name", "")
                if "billing-appeals" in ch_name.lower().replace(" ", "-").replace("_", "-"):
                    all_channel_messages.extend(ch.get("messages", []))
                    break

    # Fallback: top-level keys are channel names
    if not all_channel_messages:
        for key in slack_data:
            if key in ("channels", "messages", "users", "counters"):
                continue
            if "billing-appeals" in key.lower().replace(" ", "-").replace("_", "-"):
                val = slack_data[key]
                if isinstance(val, dict) and "messages" in val:
                    all_channel_messages.extend(val["messages"])
                elif isinstance(val, list):
                    all_channel_messages.extend(val)
                break

    if not all_channel_messages:
        return {
            "pass": False,
            "score": 0.0,
            "feedback": f"Could not find any messages in #billing-appeals channel in slack_data.json. Top-level keys: {list(slack_data.keys())}"
        }

    def get_text(msg):
        if isinstance(msg, dict):
            return msg.get("text", "") or msg.get("message", "") or msg.get("content", "") or msg.get("body", "") or ""
        elif isinstance(msg, str):
            return msg
        return ""

    def term_in_text(term, text):
        """Check if a required term appears in text, with flexible matching."""
        text_upper = text.upper()
        term_upper = term.upper()
        if term_upper in text_upper:
            return True
        # Flexible matching for specific terms
        if term == "Holloway_DOB_03141961":
            pattern = re.compile(r"holloway[\s_\-]*dob[\s_\-]*0?3[\s_\-/]*14[\s_\-/]*1961", re.IGNORECASE)
            if pattern.search(text):
                return True
            # Also accept Holloway ... 03/14/1961 style
            if re.search(r"holloway", text, re.IGNORECASE) and re.search(r"03[/\-.]14[/\-.]1961", text):
                return True
            return False
        elif term == "12/09/2025":
            if re.search(r"12[/\-.]09[/\-.]2025", text):
                return True
            return False
        elif term == "BlueCrest Commercial PPO":
            # Accept variations in spacing/casing
            pattern = re.compile(r"bluecrest\s+commercial\s+ppo", re.IGNORECASE)
            if pattern.search(text):
                return True
            return False
        elif term == "APPEAL":
            if re.search(r"appeal", text, re.IGNORECASE):
                return True
            return False
        elif term == "L1":
            if re.search(r"\bL1\b", text, re.IGNORECASE):
                return True
            # Also accept "Level 1" or "Level-1"
            if re.search(r"level[\s\-]?1", text, re.IGNORECASE):
                return True
            return False
        elif term == "PI-204":
            if re.search(r"PI[\-\s]?204", text, re.IGNORECASE):
                return True
            return False
        return False

    required_terms = ["APPEAL", "L1", "Holloway_DOB_03141961", "12/09/2025", "BlueCrest Commercial PPO", "PI-204"]

    matching_messages = []
    follow_up_count = 0

    for msg in all_channel_messages:
        text = get_text(msg)
        if not text:
            continue

        all_found = True
        for term in required_terms:
            if not term_in_text(term, text):
                all_found = False
                break
        if all_found:
            matching_messages.append(text[:500])
            # Check for FOLLOW-UP in this message
            if re.search(r"follow[\s\-_]?up", text, re.IGNORECASE):
                follow_up_count += 1

    feedback_parts = []
    score = 0.0
    passed = False

    # Check: need exactly 2 matching messages
    if len(matching_messages) >= 2:
        score += 0.6
        feedback_parts.append(f"Found {len(matching_messages)} message(s) in #billing-appeals containing all required terms.")
    else:
        feedback_parts.append(f"Expected 2 messages in #billing-appeals containing all of {required_terms}. Found {len(matching_messages)} matching message(s). Total messages in channel: {len(all_channel_messages)}.")
        # Provide diagnostic info
        sample_texts = []
        for msg in all_channel_messages[:5]:
            t = get_text(msg)
            sample_texts.append(t[:150])
        feedback_parts.append(f"Sample messages: {sample_texts}")

    # Check: exactly one message should contain FOLLOW-UP
    if follow_up_count == 1:
        score += 0.4
        feedback_parts.append("Exactly 1 matching message contains FOLLOW-UP as required.")
    else:
        feedback_parts.append(f"Expected exactly 1 matching message to contain FOLLOW-UP, but found {follow_up_count}.")

    if len(matching_messages) >= 2 and follow_up_count == 1:
        passed = True
        score = 1.0

    return {
        "pass": passed,
        "score": score,
        "feedback": " ".join(feedback_parts)
    }

